.darma-loader-darma-custom-057 {
  --s: 25px;

  --_d: calc(0.353*var(--s));
  width: calc(var(--s) + var(--_d));
  aspect-ratio: 1;
  clip-path: polygon(var(--_d) 0,100% 0,100% calc(100% - var(--_d)),calc(100% - var(--_d)) 100%,0 100%,0 var(--_d));
  background:
    conic-gradient(from -90deg at var(--s) var(--_d),
     var(--loader-secondary-color, #fff) 135deg,var(--loader-color, #666) 0 270deg,#aaa 0);
  animation: darma-loader-darma-custom-057-l1 1s infinite cubic-bezier(0.5,300,0.5,-300);
}
@keyframes darma-loader-darma-custom-057-l1{
  50%,100% {transform:translateY(0.1px)}
}

